6	describe("Game of Life - Next Generation", () => {
7	  it("should return an empty array for an empty grid", () => {
8	    expect(nextGeneration([])).toEqual([]);
9	  });
10	  it("should kill a single live cell — [(0,0)] becomes []", () => {
11	    expect(nextGeneration([[0, 0]])).toEqual([]);
12	  });
13	  it("should kill both cells of a domino (each has 1 neighbor) — Rule 1 Underpopulation: [(0,1),(1,1)] becomes []", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	  it("should keep a live cell with 2 neighbors alive — Rule 2 Survival: center of a vertical triple survives", () => {
17	    const gen0: Cell[] = [
18	      [0, 0],
19	      [0, 1],
20	      [0, 2],
21	    ];
22	    expect(nextGeneration(gen0)).toContainEqual([0, 1]);
23	  });
24	  it("should kill a live cell with more than 3 neighbors — Rule 3 Overpopulation: center (1,1) dies", () => {
25	    const gen0: Cell[] = [
26	      [0, 0],
27	      [1, 0],
28	      [2, 0],
29	      [1, 1],
30	      [0, 2],
31	      [1, 2],
32	      [2, 2],
33	    ];
34	    expect(nextGeneration(gen0)).not.toContainEqual([1, 1]);
35	  });
36	  it("should bring a dead cell with exactly 3 neighbors to life — Rule 4 Reproduction: (1,1) becomes alive", () => {
37	    const gen0: Cell[] = [
38	      [0, 0],
39	      [1, 0],
40	      [0, 1],
41	    ];
42	    expect(nextGeneration(gen0)).toContainEqual([1, 1]);
43	  });
